import{_ as r}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Configurer le Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Safety/cloudflare-api-token.md","filePath":"fr-FR/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),i={name:"fr-FR/Safety/cloudflare-api-token.md"};function l(s,e,d,u,c,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="configurer-le-cloudflare-api-token" tabindex="-1">Configurer le Cloudflare API Token <a class="header-anchor" href="#configurer-le-cloudflare-api-token" aria-label="Permalink to &quot;Configurer le Cloudflare API Token&quot;">​</a></h1><p>Certaines fonctions d’ImgBed nécessitent un Cloudflare API Token. Il sert notamment à manipuler des ressources comme R2, Workers, D1 ou KV.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Cloudflare</td><td>Créer l’API Token</td></tr><tr><td>Account ID</td><td>Identifier le compte contenant R2, Workers et autres ressources</td></tr><tr><td>Permissions nécessaires</td><td>Accorder uniquement les droits utiles</td></tr></tbody></table><h2 id="creer-un-api-token" tabindex="-1">Créer un API Token <a class="header-anchor" href="#creer-un-api-token" aria-label="Permalink to &quot;Créer un API Token&quot;">​</a></h2><ol><li>Connectez-vous au Cloudflare Dashboard.</li><li>Ouvrez <code>My Profile</code> depuis le profil en haut à droite.</li><li>Allez dans <code>API Tokens</code>.</li><li>Cliquez sur <code>Create Token</code>.</li><li>Choisissez les permissions nécessaires.</li><li>Limitez le token au compte ou à la zone concernée.</li><li>Copiez le token généré.</li></ol><p>![Cloudflare API Token](../../image/Safety/cloudflare api token截图.png)</p><p>Le token peut n’être affiché qu’une seule fois. Conservez-le dans un endroit sûr.</p><h2 id="difference-avec-global-api-key" tabindex="-1">Différence avec Global API Key <a class="header-anchor" href="#difference-avec-global-api-key" aria-label="Permalink to &quot;Différence avec Global API Key&quot;">​</a></h2><p>Cloudflare propose aussi une Global API Key, mais un API Token est généralement préférable pour ImgBed.</p><table tabindex="0"><thead><tr><th>Type</th><th>Caractéristique</th></tr></thead><tbody><tr><td>API Token</td><td>Permissions et périmètre limitables</td></tr><tr><td>Global API Key</td><td>Droits très larges sur le compte</td></tr></tbody></table><p>Un API Token avec des droits minimaux réduit les risques d’exploitation.</p><p><img src="'+r+'" alt="Voir Global API Key" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Collez le Cloudflare API Token dans l’écran de configuration correspondant dans ImgBed, puis enregistrez.</p><p>Ensuite, utilisez la fonction concernée pour tester la connexion ou la capacité et vérifier que le token fonctionne.</p><h2 id="bonnes-pratiques" tabindex="-1">Bonnes pratiques <a class="header-anchor" href="#bonnes-pratiques" aria-label="Permalink to &quot;Bonnes pratiques&quot;">​</a></h2><ul><li>Ne placez pas le token dans un dépôt public ni dans du code frontend.</li><li>Limitez les permissions et les ressources au strict nécessaire.</li><li>Supprimez dans Cloudflare les tokens inutilisés.</li><li>En cas de doute sur une fuite, révoquez le token et générez-en un nouveau.</li></ul>',18)])])}const k=a(i,[["render",l]]);export{h as __pageData,k as default};
